{% extends "_base/base.html.j2" %}


{% block title %}{{ L.doc_title }} {{ data.documentNumber }}{% endblock %}

{% set buyer   = data.documentAddress | default({}) %}
{% set sold    = ((data.effectiveAddresses or {}).soldTo) | default(buyer) %}
{% set ship    = ((data.effectiveAddresses or {}).shipTo) | default({}) %}
{% set items   = data.lineItems | default([]) %}
{% set pay     = data.payment | default({}) %}

{% set _ship_differs = ship and ship.name and (
     (ship.street or '') != (sold.street or '')
     or (ship.zipCode or '') != (sold.zipCode or '')
     or (ship.name or '') != (sold.name or '')
) %}

{% block content %}

  <div class="head-cols">
    <div class="head-cols__addr">
      {% with buyer=buyer, title='Rechnungsempfänger' %}
        {% include "_base/_partials/recipient.html.j2" %}
      {% endwith %}
    </div>
    <div class="head-cols__info">
      <section class="box-info" data-box="info" aria-labelledby="info-heading">
        <h2 id="info-heading" class="visually-hidden">{{ L.doc_title }}</h2>
        <table>
          <tbody>
            {% if data.documentDate %}<tr><th scope="row">{{ L.invoice_date }}</th><td>{{ data.documentDate | date }}</td></tr>{% endif %}
            {% if data.serviceDate %}<tr><th scope="row">{{ L.service_date }}</th><td>{{ data.serviceDate | date }}</td></tr>{% endif %}
            {% if data.customerNumber %}<tr><th scope="row">{{ L.customer_number }}</th><td>{{ data.customerNumber }}</td></tr>{% endif %}
            {% if data.customerOrderNumber %}<tr><th scope="row">{{ L.order_ref }}</th><td>{{ data.customerOrderNumber }}</td></tr>{% endif %}
            {% if buyer.vatId %}<tr><th scope="row">{{ L.customer_vat }}</th><td>{{ buyer.vatId }}</td></tr>{% endif %}
          </tbody>
        </table>
      </section>
    </div>
  </div>

  <section class="box-subject" data-box="subject">
    <h1>{{ L.doc_title }} {{ data.documentNumber }}</h1>
  </section>

  <section class="box-intro" data-box="intro"><p>{{ L.intro }}</p></section>

  {% with title=L.positions, caption=L.positions, items=items, labels=L,
          columns=['pos','article','qty','unit_price','total'] %}
    {% include "_base/_partials/items.html.j2" %}
  {% endwith %}

  {% with items=items, totals=(data.totals or {}), labels=L %}
    {% include "_base/_partials/totals.html.j2" %}
  {% endwith %}

  {% if pay.iban %}
  <section class="box-payment" data-box="payment" aria-labelledby="pay-heading">
    <h2 id="pay-heading">{{ L.payment_heading }}</h2>
    <dl class="pay-grid">
      <dt>{{ L.iban }}</dt><dd>{{ pay.iban }}</dd>
      {% if pay.bic %}<dt>{{ L.bic }}</dt><dd>{{ pay.bic }}</dd>{% endif %}
      {% if pay.bankName %}<dt>{{ L.bank }}</dt><dd>{{ pay.bankName }}</dd>{% endif %}
    </dl>
  </section>
  {% endif %}

  {% if data.bodyOutroduction %}
  <section class="box-notes" data-box="notes" aria-labelledby="terms-heading">
    <h2 id="terms-heading">{{ L.terms_heading }}</h2>
    <p>{{ data.bodyOutroduction }}</p>
  </section>
  {% endif %}

  {% if _ship_differs %}
    {% with ship=ship, title=L.ship_to %}
      {% include "_base/_partials/ship_to.html.j2" %}
    {% endwith %}
  {% endif %}

{% endblock %}

css:
/* ── Xentral Original: klassisch DIN, schwarz auf weiß, keine Farbflächen ── */
.doc-header__brand { max-width: 100%; flex: 1 1 auto; min-width: 0; }  /* Firmenname volle Breite */
.doc-header__sender { display: none; }            /* Straße/Ort oben im Header weglassen */
.box-subject h1 { font-size: 13pt; }              /* Betreff kompakter */

/* Kopf: Anschriftenfeld links, Infoblock rechts oben (klassisch Xentral/DIN) */
.head-cols { display: flex; justify-content: space-between; align-items: flex-start; gap: 10mm; margin: 8mm 0 6mm; }
.head-cols__addr { flex: 1 1 auto; min-width: 0; }
.head-cols__addr .box-recipient { margin: 0; }
.head-cols__info { flex: 0 0 64mm; }
.head-cols__info .box-info { margin: 0; }
.head-cols__info .box-info table { width: 100%; border-collapse: collapse; }
.head-cols__info .box-info th { white-space: nowrap; padding: 0.6mm 4mm 0.6mm 0; }
.head-cols__info .box-info td { text-align: right; }  /* Werte rechtsbündig */

/* abw. Lieferadresse: schlichter Block statt grauer Farbfläche */
.box-ship-to { background: none; border-left: none; border-radius: 0; border-top: 0.4pt solid #d1d5db; padding: 2mm 0 0; }

.pay-grid { display: grid; grid-template-columns: 24mm 1fr; gap: 0.5mm 4mm; margin: 0; font-size: 9.5pt; }
.pay-grid dt { color: #6b7280; }
.pay-grid dd { margin: 0; }

/* 5-Spalten-Positionen (USt erscheint nur in der Summen-Aufstellung) */
.positions-table thead th:nth-child(3) { width: 22mm; }
.positions-table thead th:nth-child(4) { width: 30mm; }
.positions-table thead th:nth-child(5) { width: 32mm; }
.positions-table thead th:nth-child(6) { display: none; }
.positions-table tbody td:nth-child(6) { display: none; }

/* Pflichtangaben (§35a GmbHG / §14 UStG) auf jeder Seite.
   Live aus der Mandanten-/Projekt-Konfiguration; hier mit Beispieldaten.
   (HRB/Amtsgericht/Bank liegen nicht in der V3-company-Payload → Config.) */
@page {
  @top-right { content: none; }
  @bottom-left {
    content: "Beispiel Handels GmbH · Marktplatz 1, 10115 Berlin \A Amtsgericht Charlottenburg · HRB 123456 \A Geschäftsführer: Max Beispiel";
    font-size: 6.5pt; line-height: 1.4; color: #6b7280;
    font-family: 'Helvetica', 'Arial', sans-serif; white-space: pre-line;
    vertical-align: top; padding-top: 4mm;
  }
  @bottom-center {
    content: "Seite " counter(page) " von " counter(pages);
    font-size: 6.5pt; color: #6b7280;
    font-family: 'Helvetica', 'Arial', sans-serif; vertical-align: top; padding-top: 4mm;
  }
  @bottom-right {
    content: "USt-IdNr. DE123456789 · St.-Nr. 13/456/78901 \A Commerzbank Berlin · BIC COBADEFFXXX \A IBAN DE89 3704 0044 0532 0130 00";
    font-size: 6.5pt; line-height: 1.4; color: #6b7280;
    font-family: 'Helvetica', 'Arial', sans-serif; white-space: pre-line;
    text-align: right; vertical-align: top; padding-top: 4mm;
  }
}
